final:
module SR_FlipFlop (
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q,
    output reg Qn
);
    always @(posedge clk) begin
        if (S && ~R) begin
            obf_Q <= 1;
            Qn <= 0;
        end else if (~S && R) begin
            obf_Q <= 0;
            Qn <= 1;
        end else if (S && R) begin
            // Invalid state for SR flip-flop, can be handled as needed
            obf_Q <= obf_Q; // Maintain state
            Qn <= ~obf_Q; // Complement of obf_Q
        end
    end
endmodule
